function validate(args, output) {
    const barcodes = args[0];
    if (!Array.isArray(output)) return false;
    if (output.length !== barcodes.length) return false;
    const a = new Map(), b = new Map();
    for (const v of barcodes) a.set(v, (a.get(v) || 0) + 1);
    for (const v of output) b.set(v, (b.get(v) || 0) + 1);
    if (a.size !== b.size) return false;
    for (const [k, v] of a) if (b.get(k) !== v) return false;
    for (let i = 1; i < output.length; i++) {
        if (output[i] === output[i - 1]) return false;
    }
    return true;
}

