class Solution:
    def rearrangeBarcodes(self, barcodes):
        from collections import Counter
        cnt = Counter(barcodes)
        order = sorted(cnt.keys(), key=lambda v: (-cnt[v], v))
        seq = []
        for v in order:
            seq.extend([v] * cnt[v])
        n = len(barcodes)
        res = [0] * n
        pos = 0
        for i in range(0, n, 2):
            res[i] = seq[pos]; pos += 1
        for i in range(1, n, 2):
            res[i] = seq[pos]; pos += 1
        return res

