var rearrangeBarcodes = function(barcodes) {
    const cnt = new Map();
    for (const v of barcodes) cnt.set(v, (cnt.get(v) || 0) + 1);
    const order = [...cnt.keys()].sort((a, b) => {
        const d = cnt.get(b) - cnt.get(a);
        return d !== 0 ? d : a - b;
    });
    const seq = [];
    for (const v of order) {
        for (let k = 0; k < cnt.get(v); k++) seq.push(v);
    }
    const n = barcodes.length;
    const res = new Array(n);
    let pos = 0;
    for (let i = 0; i < n; i += 2) res[i] = seq[pos++];
    for (let i = 1; i < n; i += 2) res[i] = seq[pos++];
    return res;
};
